   214→    @Override
   215→    public KafkaChannel buildChannel(String id, SelectionKey key, int maxReceiveSize,
   216→                                     MemoryPool memoryPool, ChannelMetadataRegistry metadataRegistry) throws KafkaException {
   217→        TransportLayer transportLayer = null;
   218→        try {
   219→            SocketChannel socketChannel = (SocketChannel) key.channel();
   220→            Socket socket = socketChannel.socket();
   221→            transportLayer = buildTransportLayer(id, key, socketChannel, metadataRegistry);
   222→            final TransportLayer finalTransportLayer = transportLayer;
   223→            Supplier<Authenticator> authenticatorCreator;
   224→            if (connectionMode == ConnectionMode.SERVER) {
   225→                authenticatorCreator = () -> buildServerAuthenticator(configs,
   226→                        Collections.unmodifiableMap(saslCallbackHandlers),
   227→                        id,
   228→                        finalTransportLayer,
   229→                        Collections.unmodifiableMap(subjects),
   230→                        Collections.unmodifiableMap(connectionsMaxReauthMsByMechanism),
   231→                        metadataRegistry);
   232→            } else {
   233→                LoginManager loginManager = loginManagers.get(clientSaslMechanism);
   234→                authenticatorCreator = () -> buildClientAuthenticator(configs,
   235→                        saslCallbackHandlers.get(clientSaslMechanism),
   236→                        id,
   237→                        socket.getInetAddress().getHostName(),
   238→                        loginManager.serviceName(),
   239→                        finalTransportLayer,
   240→                        subjects.get(clientSaslMechanism));
   241→            }
